import os
import re
from pathlib import Path

sites_dir = Path("/home/vadim/Projects/zodiacid/sites/zodiacid")

issues = []

for html_file in sorted(sites_dir.rglob("*.html")):
    # Skip partials directory
    if "partials" in html_file.parts:
        continue
    # Skip sitemap.xml and other non-.html files
    if html_file.suffix != ".html":
        continue

    with open(html_file, 'r', encoding='utf-8') as f:
        content = f.read()

    # Extract file path relative to sites/zodiacid
    rel_path = html_file.relative_to(sites_dir)

    # Check if this is a 404 file
    is_404 = html_file.name == "404.html"

    # Find all hreflang link tags (not in navigation)
    hreflang_pattern = r'<link\s+rel="alternate"\s+hreflang="([^"]+)"\s+href="([^"]+)"'
    hreflang_matches = re.findall(hreflang_pattern, content)

    if is_404:
        if hreflang_matches:
            issues.append(f"ERROR: {rel_path} is 404.html but has {len(hreflang_matches)} hreflang link tags")
    else:
        # Regular page should have 4 hreflang links: en, ru, et, x-default
        if not hreflang_matches:
            issues.append(f"ERROR: {rel_path} has NO hreflang link tags")
        elif len(hreflang_matches) != 4:
            issues.append(f"ERROR: {rel_path} has {len(hreflang_matches)} hreflang link tags (expected 4). Found: {[m[0] for m in hreflang_matches]}")
        else:
            # Check all 4 required tags are present
            langs = {m[0] for m in hreflang_matches}
            required = {'en', 'ru', 'et', 'x-default'}
            if langs != required:
                issues.append(f"ERROR: {rel_path} missing languages: {required - langs}. Has: {langs}")
            else:
                # Validate URLs for each language
                for lang, url in hreflang_matches:
                    if lang == "en" or lang == "x-default":
                        # Should NOT have /en/ or language prefix for EN
                        if f"/{lang}/" in url:
                            issues.append(f"ERROR: {rel_path} has en hreflang pointing to /{lang}/ URL: {url}")
                    elif lang == "ru":
                        if "/ru/" not in url:
                            issues.append(f"ERROR: {rel_path} has ru hreflang NOT pointing to /ru/ URL: {url}")
                    elif lang == "et":
                        if "/et/" not in url:
                            issues.append(f"ERROR: {rel_path} has et hreflang NOT pointing to /et/ URL: {url}")

if issues:
    for issue in issues:
        print(issue)
    print(f"\nTotal issues: {len(issues)}")
else:
    print("All HTML files have correct hreflang annotations!")

